  "questionProse": [
    "वर्स्ट केस में हीप सॉर्ट की टाइम कॉम्प्लेक्सिटी क्या होगी?"
  ],
  "explanationProse": [
    "हीप सॉर्ट की वर्स्ट-केस टाइम कॉम्प्लेक्सिटी हमेशा O(n log n) ही रहती है। ऐसा इसलिए है क्योंकि एल्गोरिदम को डेटा को हीप स्ट्रक्चर में व्यवस्थित करना पड़ता है और फिर बार-बार अधिकतम एलिमेंट को निकालना पड़ता है, जिसमें हर बार लॉगरिदमिक समय लगता है।"
  ]
}
